{"title":"Bilingual Welcome Card","lesson":"L1 · HTML Foundations · HTML Text","desc":"Build a small welcome card with one left-to-right English line and one right-to-left Arabic line. Use the <code>dir</code> attribute on each paragraph so the text flows the correct way.","startFile":"html","goals":[{"id":"has-ltr-paragraph","label":"Has a paragraph with left-to-right direction","target":"html","kind":"regex","rule":"<p[^>]*dir\s*=\s*["']ltr["'][^>]*>","flags":"i","minCount":1},{"id":"has-rtl-paragraph","label":"Has a paragraph with right-to-left direction","target":"html","kind":"regex","rule":"<p[^>]*dir\s*=\s*["']rtl["'][^>]*>","flags":"i","minCount":1},{"id":"two-paragraphs","label":"Has at least 2 paragraphs","target":"html","kind":"regex","rule":"<p[\s>]","flags":"ig","minCount":2}],"targetHtml":"<div style="font-family:Arial,sans-serif;border:2px solid #7c9cff;border-radius:12px;padding:14px;max-width:320px;background:#f7f9ff;line-height:1.6;">
