  <!-- Use <dfn> to mark the special term being defined. -->
  <p><dfn>Onomatopoeia</dfn> is a word that sounds like the noise it names.</p>

  <!-- Use <q> for a short quote that sits inside a sentence. -->
  <p>One student said, <q>This is a fun word to say!</q></p>

  <!-- Use <blockquote> for a longer quoted idea shown as its own block. -->
  <blockquote>Words can paint sounds in your mind before you even hear them.</blockquote>
</section>","css":"body {
  font-family: Arial, sans-serif;
  background: #f5f7fb;
  padding: 24px;
}

section {
  max-width: 520px;
  background: #fafafa;
  border: 2px solid #d7d7d7;
  border-radius: 10px;
  padding: 12px;
  line-height: 1.5;
}

blockquote {
  margin: 10px 0 0 0;
  padding-left: 12px;
  border-left: 4px solid #999;
}","js":"// No JavaScript is needed for this HTML text challenge."},"pair":{"html":"<section>
