<style>
  /* Collapse touching borders into single lines so the table looks tidy. */
  table {
    border-collapse: collapse;
    border-style: solid;
    border-color: #2a6f97;
  }

  /* Give every header and data cell the same border and some space inside. */
  th,
  td {
    border-style: solid;
    border-color: #2a6f97;
    padding: 8px;
  }

  /* A light background helps the heading row stand out. */
  th {
    background: #d9f0ff;
  }
</style>

<!-- The table holds rows of lunch menu information. -->
<table>
  <tr>
    <th>Food</th>
    <th>Day</th>
  </tr>
  <tr>
    <td>Tacos</td>
