{"title":"Merge Table Cells","lesson":"L1 · HTML Foundations · HTML Tables","desc":"Build a small class timetable using a table. Use <code>colspan</code> once to stretch a heading across columns and <code>rowspan</code> once to make one subject cover two rows.","startFile":"html","goals":[{"id":"has-table","label":"Has a table","target":"html","kind":"regex","rule":"<table[\s>]","flags":"i","minCount":1},{"id":"uses-colspan","label":"Uses colspan","target":"html","kind":"regex","rule":"colspan\s*=\s*["']?2["']?","flags":"i","minCount":1},{"id":"uses-rowspan","label":"Uses rowspan","target":"html","kind":"regex","rule":"rowspan\s*=\s*["']?2["']?","flags":"i","minCount":1},{"id":"has-rows","label":"Has at least 3 table rows","target":"html","kind":"regex","rule":"<tr[\s>]","flags":"ig","minCount":3}],"targetHtml":"<table style="border-collapse:collapse;font-family:Arial,sans-serif;text-align:center;">
  <tr>
    <th colspan="2" style="border:1px solid #555;padding:8px;background:#dff4ff;">Class Timetable</th>
  </tr>
  <tr>
    <td rowspan="2" style="border:1px solid #555;padding:8px;background:#fff4cc;">Science</td>
    <td style="border:1px solid #555;padding:8px;">Room 1</td>
  </tr>
  <tr>
    <td style="border:1px solid #555;padding:8px;">Room 2</td>
  </tr>
</table>","targetSub":"A 2-column timetable with one top cell merged across columns and one left cell merged down two rows.","files":{"guide":{"html":"<!-- This table shows a tiny class timetable. -->
<!-- <table> starts the whole table. -->
<table>
  <!-- The first row is a heading row for the whole table. -->
  <tr>
    <!-- colspan="2" makes this heading stretch across both columns. -->
    <th colspan="2">Class Timetable</th>
  </tr>

  <!-- This row starts the timetable details. -->
  <tr>
    <!-- rowspan="2" makes Science cover this row and the next row too. -->
    <td rowspan="2">Science</td>
    <!-- This cell sits to the right of Science in the first detail row. -->
    <td>Room 1</td>
  </tr>

  <!-- This is the third row. -->
  <tr>
    <!-- We only need one cell here because Science is still stretching down. -->
    <td>Room 2</td>
  </tr>
</table>","css":"table {
